SET NAMES utf8mb4;

UPDATE `mb_client_decoration_scheme`
SET `schema` = JSON_SET(
      `schema`,
      '$.pageStyle.backgroundColorEnd', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.pageStyle.backgroundColorEnd')), ''),
      '$.pageStyle.backgroundColorStart', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.pageStyle.backgroundColorStart')), ''),
      '$.pageStyle.backgroundGradientDirection', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.pageStyle.backgroundGradientDirection')), 'horizontal'),
      '$.pageStyle.backgroundMode', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.pageStyle.backgroundMode')), 'color'),
      '$.pageStyle.background_image', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.pageStyle.background_image')), ''),
      '$.pageStyle.padding', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.padding'), CAST('23' AS JSON)),
      '$.pageStyle.paddingBottom', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.paddingBottom'), CAST('24' AS JSON)),
      '$.pageStyle.paddingLeft', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.paddingLeft'), JSON_EXTRACT(`schema`, '$.pageStyle.paddingX'), CAST('28' AS JSON)),
      '$.pageStyle.paddingRight', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.paddingRight'), JSON_EXTRACT(`schema`, '$.pageStyle.paddingX'), CAST('28' AS JSON)),
      '$.pageStyle.paddingTop', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.paddingTop'), JSON_EXTRACT(`schema`, '$.pageStyle.paddingY'), CAST('10' AS JSON)),
      '$.pageStyle.paddingX', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.paddingX'), CAST('28' AS JSON)),
      '$.pageStyle.paddingY', COALESCE(JSON_EXTRACT(`schema`, '$.pageStyle.paddingY'), CAST('17' AS JSON)),
      '$.modules[0].props.shadowBlur', COALESCE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowBlur'), CAST('30' AS JSON)),
      '$.modules[0].props.shadowColor', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowColor')), '#0f172a'),
      '$.modules[0].props.shadowEnabled', COALESCE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowEnabled'), CAST('false' AS JSON)),
      '$.modules[0].props.shadowOffsetX', COALESCE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowOffsetX'), CAST('0' AS JSON)),
      '$.modules[0].props.shadowOffsetY', COALESCE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowOffsetY'), CAST('12' AS JSON)),
      '$.modules[0].props.shadowOpacity', COALESCE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowOpacity'), CAST('14' AS JSON)),
      '$.modules[0].props.shadowSpread', COALESCE(JSON_EXTRACT(`schema`, '$.modules[0].props.shadowSpread'), CAST('0' AS JSON)),
      '$.modules[1].props.shadowBlur', COALESCE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowBlur'), CAST('30' AS JSON)),
      '$.modules[1].props.shadowColor', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowColor')), '#0f172a'),
      '$.modules[1].props.shadowEnabled', COALESCE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowEnabled'), CAST('false' AS JSON)),
      '$.modules[1].props.shadowOffsetX', COALESCE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowOffsetX'), CAST('0' AS JSON)),
      '$.modules[1].props.shadowOffsetY', COALESCE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowOffsetY'), CAST('12' AS JSON)),
      '$.modules[1].props.shadowOpacity', COALESCE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowOpacity'), CAST('14' AS JSON)),
      '$.modules[1].props.shadowSpread', COALESCE(JSON_EXTRACT(`schema`, '$.modules[1].props.shadowSpread'), CAST('0' AS JSON)),
      '$.modules[2].props.shadowBlur', COALESCE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowBlur'), CAST('30' AS JSON)),
      '$.modules[2].props.shadowColor', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowColor')), '#0f172a'),
      '$.modules[2].props.shadowEnabled', COALESCE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowEnabled'), CAST('false' AS JSON)),
      '$.modules[2].props.shadowOffsetX', COALESCE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowOffsetX'), CAST('0' AS JSON)),
      '$.modules[2].props.shadowOffsetY', COALESCE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowOffsetY'), CAST('12' AS JSON)),
      '$.modules[2].props.shadowOpacity', COALESCE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowOpacity'), CAST('14' AS JSON)),
      '$.modules[2].props.shadowSpread', COALESCE(JSON_EXTRACT(`schema`, '$.modules[2].props.shadowSpread'), CAST('0' AS JSON)),
      '$.modules[3].props.shadowBlur', COALESCE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowBlur'), CAST('30' AS JSON)),
      '$.modules[3].props.shadowColor', COALESCE(JSON_UNQUOTE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowColor')), '#0f172a'),
      '$.modules[3].props.shadowEnabled', COALESCE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowEnabled'), CAST('false' AS JSON)),
      '$.modules[3].props.shadowOffsetX', COALESCE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowOffsetX'), CAST('0' AS JSON)),
      '$.modules[3].props.shadowOffsetY', COALESCE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowOffsetY'), CAST('12' AS JSON)),
      '$.modules[3].props.shadowOpacity', COALESCE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowOpacity'), CAST('14' AS JSON)),
      '$.modules[3].props.shadowSpread', COALESCE(JSON_EXTRACT(`schema`, '$.modules[3].props.shadowSpread'), CAST('0' AS JSON))
    ),
    `update_time` = CURRENT_TIMESTAMP
WHERE `type` = 'profile'
  AND `is_system` = 1
  AND `delete_time` IS NULL;
